    { id: "v8", front: "What cost range covers the termite letter on most net sheets you prepare?", back: "$75–$150 covers the typical cost of a wood-destroying insect report." },
    { id: "v9", front: "How would you explain the cost of a WDIR to a first-time seller who's never seen a net sheet before?", back: "Tell them the wood-destroying insect report — sometimes called the termite letter — usually runs between $75 and $150." },
    { id: "v10", front: "For quick mental math on a seller's proceeds, what number do you use for the pest inspection report?", back: "Use $75–$150 as your working estimate for the WDIR." }
